from pathlib import Path
import json, html
import pandas as pd
ROOT=Path(__file__).resolve().parents[1]
monthly=pd.read_csv(ROOT/'data/processed/monthly_kpis.csv')
genre=pd.read_csv(ROOT/'data/processed/genre_performance.csv')
segments=pd.read_csv(ROOT/'data/processed/viewer_segments.csv')
content=pd.read_csv(ROOT/'data/raw/content_library.csv')
users=pd.read_csv(ROOT/'data/raw/users.csv')
wh=pd.read_csv(ROOT/'data/raw/watch_history.csv')
reviews=pd.read_csv(ROOT/'data/processed/review_sentiment.csv')
metrics=json.loads((ROOT/'models/model_metrics.json').read_text())
revenue=monthly['Revenue_USD'].sum(); watch_hours=monthly['Watch_Hours'].sum(); sessions=len(wh); churn=(users['Churn_Status'].eq('Churned')).mean(); completion=wh['Completion_Rate'].mean(); premium=(users['Subscription_Type'].eq('Premium')).mean()
seg=segments.groupby('Viewer_Segment',as_index=False).agg(Users=('User_ID','count'),Watch_Minutes=('total_watch_minutes','sum'),Avg_Completion=('avg_completion','mean'),Revenue=('revenue','sum')).sort_values('Watch_Minutes',ascending=False)
country=users.merge(segments,on=['User_ID','Age','Country','Subscription_Type','Churn_Status']).groupby('Country',as_index=False).agg(Users=('User_ID','count'),Watch_Minutes=('total_watch_minutes','sum'),Churned=('Churn_Status',lambda s:(s=='Churned').mean())).sort_values('Watch_Minutes',ascending=False)
top_content=wh.merge(content,on='Content_ID').groupby(['Title','Genre','Content_Type'],as_index=False).agg(Sessions=('Session_ID','count'),Avg_Completion=('Completion_Rate','mean'),Watch_Minutes=('Watch_Duration','sum')).sort_values('Watch_Minutes',ascending=False).head(10)

def num(x): return f'{x:,.0f}'
def pct(x): return f'{x*100:.1f}%'
def usd(x): return f'${x/1_000_000:,.2f}M'
def bars(df,label,value,color='linear-gradient(90deg,#6d2b21,#c8a45d)',limit=8):
    rows=df.head(limit).to_dict('records'); mx=max([float(r[value]) for r in rows] or [1]); out=[]
    for r in rows:
        w=float(r[value])/mx*100; out.append(f'<div class="bar"><b>{html.escape(str(r[label]))}</b><span><i style="width:{w:.1f}%;background:{color}"></i></span><em>{num(float(r[value]))}</em></div>')
    return ''.join(out)
def table(df, cols):
    h=''.join(f'<th>{c.replace("_"," ")}</th>' for c in cols); rows=''
    for _,r in df.head(8).iterrows():
        rows+='<tr>'+''.join(f'<td>{html.escape(str(round(r[c],2) if isinstance(r[c],float) else r[c]))}</td>' for c in cols)+'</tr>'
    return f'<table><thead><tr>{h}</tr></thead><tbody>{rows}</tbody></table>'
vals=monthly['Watch_Hours'].tolist(); labels=monthly['Month'].tolist(); mn=min(vals); mx=max(vals); pts=[]
for i,v in enumerate(vals):
    x=30+i*(900-60)/(len(vals)-1); y=245-((v-mn)/(mx-mn))*210; pts.append(f'{x:.1f},{y:.1f}')
line=' '.join(pts)
chart=f'<svg viewBox="0 0 900 280"><defs><linearGradient id="a" x1="0" x2="1"><stop stop-color="#6d2b21"/><stop offset="1" stop-color="#c8a45d"/></linearGradient><filter id="polish"><feGaussianBlur stdDeviation="4"/><feMerge><feMergeNode/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><polyline points="{line}" fill="none" stroke="url(#a)" stroke-width="5" stroke-linecap="round" filter="url(#polish)"/><text x="30" y="272" fill="#8fa0d6">{labels[0]}</text><text x="760" y="272" fill="#8fa0d6">{labels[-1]}</text></svg>'
html_doc=f'''<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Netflix Content Strategy Analytics | Old-Money BI</title><style>
:root{{--bg:#160d07;--red:#6d2b21;--brass:#c8a45d;--copper:#8a6534;--green:#1f4d36;--panel:#3a2415ee;--line:rgba(200,164,93,.28);--text:#f7f0df;--muted:#b9a98d}}*{{box-sizing:border-box}}body{{margin:0;background:radial-gradient(circle at 20% 0,#4a0710 0,transparent 28%),radial-gradient(circle at 85% 10%,#003b5e 0,transparent 28%),linear-gradient(135deg,#030207,#2a170c 55%,#090603);color:var(--text);font-family:Inter,Arial,sans-serif}}body:before{{content:"";position:fixed;inset:0;background-image:linear-gradient(rgba(229,9,20,.13) 1px,transparent 1px),linear-gradient(90deg,rgba(0,245,255,.1) 1px,transparent 1px);background-size:44px 44px;mask-image:linear-gradient(to bottom,#000,transparent 82%);pointer-events:none}}.wrap{{width:min(1450px,94vw);margin:auto;padding:34px 0 70px;position:relative}}.hero{{padding:38px;border:1px solid #6d1523;border-radius:30px;background:linear-gradient(135deg,rgba(18,22,47,.94),rgba(5,8,22,.74));box-shadow:0 0 55px rgba(229,9,20,.18),inset 0 0 80px rgba(0,245,255,.05)}}.eyebrow{{color:var(--brass);letter-spacing:.22em;text-transform:uppercase;font-size:12px;font-weight:900}}h1{{font-size:clamp(38px,5.5vw,82px);line-height:.92;margin:12px 0;text-shadow:0 0 24px rgba(229,9,20,.55)}}.grad{{background:linear-gradient(90deg,var(--red),var(--copper),var(--brass));-webkit-background-clip:text;color:transparent}}p{{color:var(--muted);font-size:18px;line-height:1.55;max-width:980px}}.chips{{display:flex;gap:10px;flex-wrap:wrap;margin-top:22px}}.chip{{border:1px solid #3e4a81;background:#080e28cc;border-radius:999px;padding:9px 14px;color:#dfe7ff}}.grid{{display:grid;grid-template-columns:repeat(12,1fr);gap:18px;margin-top:18px}}.card{{grid-column:span 3;background:linear-gradient(180deg,rgba(17,22,47,.94),rgba(7,10,28,.92));border:1px solid var(--line);border-radius:22px;padding:20px;box-shadow:0 18px 55px rgba(0,0,0,.35),0 0 24px rgba(0,245,255,.06)}}.wide{{grid-column:span 8}}.side{{grid-column:span 4}}.half{{grid-column:span 6}}.full{{grid-column:span 12}}.label{{color:var(--muted);text-transform:uppercase;letter-spacing:.12em;font-size:13px}}.metric{{font-size:clamp(27px,3vw,43px);font-weight:950;margin-top:8px}}.red{{color:var(--red);text-shadow:0 0 18px rgba(229,9,20,.6)}}.brass{{color:var(--brass);text-shadow:0 0 18px rgba(0,245,255,.5)}}.green{{color:var(--green);text-shadow:0 0 18px rgba(157,255,0,.4)}}h2{{margin:0 0 14px;font-size:24px}}svg{{width:100%;height:auto}}.bar{{display:grid;grid-template-columns:170px 1fr 110px;gap:12px;align-items:center;margin:12px 0}}.bar b{{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}}.bar span{{height:12px;border-radius:99px;background:#080d25;border:1px solid #28305c;overflow:hidden}}.bar i{{display:block;height:100%;border-radius:99px;box-shadow:0 0 18px currentColor}}.bar em{{font-style:normal;color:var(--brass);font-weight:800;text-align:right}}table{{width:100%;border-collapse:collapse}}th,td{{padding:11px 12px;border-bottom:1px solid #252c55;text-align:left;font-size:13px}}th{{color:var(--brass);background:#090f2b;text-transform:uppercase}}.insights{{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}}.insight{{background:#090f2c;border-left:3px solid var(--red);border-radius:14px;padding:14px;color:#dfe7ff}}.footer{{text-align:center;color:#8994c4;margin-top:30px}}@media(max-width:900px){{.card,.wide,.side,.half{{grid-column:span 12}}.bar{{grid-template-columns:1fr}}.insights{{grid-template-columns:1fr}}}}
</style></head><body><main class="wrap"><section class="hero"><div class="eyebrow">Streaming Strategy Boardroom • Python + SQL + ML + BI</div><h1>Netflix Content Strategy & Viewer Engagement <span class="grad">Analytics Dashboard</span></h1><p>A cinematic old-money analytics platform for OTT leadership: viewer behavior, content performance, churn risk, subscription revenue, recommendations, and global engagement intelligence.</p><div class="chips"><span class="chip">Executive Overview</span><span class="chip">Viewer Analytics</span><span class="chip">Content Performance</span><span class="chip">Revenue Analytics</span><span class="chip">Churn Analysis</span><span class="chip">Global Engagement</span></div></section><section class="grid">
<div class="card"><div class="label">Watch Sessions</div><div class="metric red">{num(sessions)}</div></div><div class="card"><div class="label">Total Watch Time</div><div class="metric brass">{num(watch_hours)} hrs</div></div><div class="card"><div class="label">Churn Rate</div><div class="metric">{pct(churn)}</div></div><div class="card"><div class="label">Revenue Proxy</div><div class="metric green">{usd(revenue)}</div></div>
<div class="card wide"><h2>Monthly Watch-Time Pulse</h2>{chart}</div><div class="card side"><h2>North Star Metrics</h2><div class="label">Avg Completion</div><div class="metric brass">{pct(completion)}</div><div class="label">Premium Adoption</div><div class="metric red">{pct(premium)}</div><div class="label">Churn Model ROC-AUC</div><div class="metric green">{metrics['roc_auc']:.2f}</div></div>
<div class="card half"><h2>Most Watched Genres</h2>{bars(genre,'Genre','Watch_Hours')}</div><div class="card half"><h2>Global Engagement</h2>{bars(country,'Country','Watch_Minutes','linear-gradient(90deg,#c8a45d,#1f4d36)')}</div>
<div class="card half"><h2>Viewer Segments</h2>{table(seg,['Viewer_Segment','Users','Watch_Minutes','Avg_Completion','Revenue'])}</div><div class="card half"><h2>Top Performing Titles</h2>{table(top_content,['Title','Genre','Content_Type','Sessions','Avg_Completion'])}</div>
<div class="card full"><h2>Strategic Insights</h2><div class="insights"><div class="insight"><b>Genre retention:</b> high-completion genres deserve stronger home-page placement and renewal prioritization.</div><div class="insight"><b>Mobile behavior:</b> mobile viewers over-index on short, frequent sessions, making them prime targets for binge nudges.</div><div class="insight"><b>Revenue mix:</b> Premium users contribute outsized revenue and should receive early access and 4K-first content campaigns.</div><div class="insight"><b>Churn warning:</b> low watch time + low completion is the clearest intervention trigger for win-back journeys.</div></div></div>
</section><div class="footer">Built with synthetic OTT data • 132K sessions • 24K users • 35 SQL queries • Streamlit app • ML segmentation/churn/recommendations</div></main></body></html>'''
for p in [ROOT/'public/index.html', ROOT/'dashboard/executive_dashboard.html']:
    p.write_text(html_doc)
print('Built static dashboard', len(html_doc), 'chars')
